export const MAX_POSTS_LIMIT = 100;

export type DeleteResult<T = any> = {
  success: boolean;
  error?: { message: string; status?: number };
  deleted?: T | null;
  reason?: 'not_found' | 'not_owner' | 'permission' | 'network';
