export const SHADOW_USER_ID = getShadowIdentity();

// --- 2. INITIALIZE CLIENT ---
const supabase = createClient(SUPABASE_URL, SUPABASE_KEY, {
  global: {
    headers: {
      'x-shadow-user-id': SHADOW_USER_ID 
    }
  }
});

export const getSupabase = () => supabase;

// --- 3. AUTHENTICATION ---
let isUsingShadowMode = false;

// Expose status for UI checks
export const isGuest = () => isUsingShadowMode;

export const initializeAuth = async (): Promise<string> => {
  try {
    const { data: { session } } = await supabase.auth.getSession();

    if (session?.user) {
      console.log("[Echo] Restored valid session:", session.user.id);
      isUsingShadowMode = false;
      return session.user.id;
    }

    console.log("[Echo] Attempting Anonymous Sign-in...");
    const { data, error } = await supabase.auth.signInAnonymously();

    if (error) {
      if (
        error.message.includes("Anonymous sign-ins are disabled") || 
        error.status === 400 || 
        error.code === 'anonymous_provider_disabled'
      ) {
        console.warn("[Echo] Anonymous Auth disabled. Switching to Shadow Mode.");
        isUsingShadowMode = true;
        return SHADOW_USER_ID;
      }
      throw error;
    }

    if (data.user) {
        isUsingShadowMode = false;
        return data.user.id;
    }

    // Fallback if no user returned
    isUsingShadowMode = true;
    return SHADOW_USER_ID;

  } catch (e: any) {
    console.error("[Echo] Auth initialization error (using Shadow Mode):", formatError(e));
    isUsingShadowMode = true;
    return SHADOW_USER_ID;
  }
};

export const getEffectiveUserId = async (): Promise<string> => {
  const { data: { session } } = await supabase.auth.getSession();
  if (session?.user) {
      return session.user.id;
  }
  return SHADOW_USER_ID;
};

// --- DATA MAPPING ---

const mapRowToComment = (row: any): Comment => ({
  id: row.id,
  author: {
    nickname: row.nickname || 'Anonymous', 
    avatarSeed: row.avatar_seed || row.nickname || 'default',
    isAi: false, 
    userId: row.user_id
  },
  content: row.content || row.body || '',
  timestamp: new Date(row.created_at).getTime(),
  likes: 0 
});

const mapRowToPost = (row: any): Post => ({
  id: row.id,
  author: {
    nickname: row.nickname,
    avatarSeed: row.avatar_seed,
    isAi: false,
    userId: row.user_id 
  },
  content: row.content,
  tags: row.tags || [],
  timestamp: new Date(row.created_at).getTime(),
  likes: row.likes,
  comments: (row.comments || []).map(mapRowToComment).sort((a: Comment, b: Comment) => a.timestamp - b.timestamp)
});

// --- API METHODS ---

export const fetchPosts = async (): Promise<Post[]> => {
  try {
    const { data, error } = await supabase
      .from('posts')
      .select(`
        *,
        comments (
          id,
          content,
          body,
          nickname,
          avatar_seed,
          user_id,
          created_at
        )
      `)
      .order('created_at', { ascending: false })
      .limit(MAX_POSTS_LIMIT);

    if (error) throw error;
    return (data || []).map(mapRowToPost);
  } catch (error) {
    console.error("[Echo] Fetch Posts Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

export const createPost = async (nickname: string, content: string, tags: string[]): Promise<Post | null> => {
  if (!content || content.trim().length === 0) throw new Error("Content cannot be empty");
  if (content.length > 2000) throw new Error("Content exceeds 2000 characters");

  try {
    const { data, error } = await supabase
      .from('posts')
      .insert([{
        nickname,
        content,
        tags,
        avatar_seed: nickname,
        likes: 0
      }])
      .select()
      .single();

    if (error) throw error;

    cleanUpOldPosts(supabase);
    return mapRowToPost({ ...data, comments: [] });
  } catch (error) {
    console.error("[Echo] Create Post Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

/**
 * deletePost - Service layer function to delete a post safely with ownership pre-check.
 * @param supabase - SupabaseClient (from @supabase/supabase-js) bound to the user's session
 * @param postId - id of the post to delete
 * @param currentUserId - the currently-authenticated user's id (string) OR null for guest
 */
export async function deletePost(
  supabase: SupabaseClient,
  postId: string,
  currentUserId: string | null
): Promise<DeleteResult> {
  try {
    // 1) Fetch the post user_id to check ownership
    const { data: rows, error: fetchErr } = await supabase
      .from('posts')
      .select('id, user_id, nickname, content')
      .eq('id', postId)
      .limit(1)
      .maybeSingle();

    if (fetchErr) {
      // Network or permission to read failed
      return {
        success: false,
        error: { message: fetchErr.message, status: fetchErr.status },
        reason: fetchErr.status === 403 ? 'permission' : 'network',
      };
    }

    if (!rows) {
      return { success: false, error: { message: 'Post not found' }, reason: 'not_found' };
    }

    const postUserId: string | null = rows.user_id ?? null;

    // 2) Resolve caller identity - currentUserId should come from your app's auth wrapper
    // If you allow shadow/guest users, your app should supply the shadow id as currentUserId.
    if (!currentUserId) {
      return {
        success: false,
        error: { message: 'Not authenticated' },
        reason: 'not_owner',
      };
    }

    // 3) Ownership check
    if (postUserId !== currentUserId) {
      return {
        success: false,
        error: { message: 'You are not the owner of this post' },
        reason: 'not_owner',
      };
    }

    // 4) Attempt the delete
    const { data: deleted, error: deleteErr } = await supabase
      .from('posts')
      .delete()
      .eq('id', postId)
      .select()
      .maybeSingle();

    if (deleteErr) {
      // Final safeguard: RLS could deny this even if pre-check passed (race conditions)
      return {
        success: false,
        error: { message: deleteErr.message, status: deleteErr.status },
        reason: deleteErr.status === 403 ? 'permission' : 'network',
      };
    }

    return { success: true, deleted, deleted: deleted ?? null };
  } catch (err: any) {
    return {
      success: false,
      error: { message: err?.message ?? 'Unexpected error' },
      reason: 'network',
    };
  }
}

// --- COMMENTS ---

export const createComment = async (postId: string, content: string, nickname: string): Promise<Comment> => {
  if (!validateUUID(postId)) console.warn("Potential Invalid UUID for comment parent", postId);

  if (!content || content.trim().length === 0) throw new Error("Comment cannot be empty");
  if (content.length > 2000) throw new Error("Comment exceeds 2000 characters");

  try {
    const { data, error } = await supabase
      .from('comments')
      .insert([{
        post_id: postId,
        content: content,
        body: content,
        nickname,
        avatar_seed: nickname
      }])
      .select()
      .single();

    if (error) throw error;

    return mapRowToComment(data);
  } catch (error) {
    console.error("[Echo] Create Comment Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

export const deleteComment = async (commentId: string): Promise<void> => {
  if (!commentId) throw new Error("Invalid Comment ID");

  // 1. Resolve Identity
  const { data: { session }, error: sessionError } = await supabase.auth.getSession();

  if (sessionError || !session?.user) {
      if (isUsingShadowMode) {
          throw new Error("Guest users cannot delete comments. Please sign in.");
      }
      throw new Error("Authentication required to delete comments.");
  }

  const currentUserId = session.user.id;

  // 2. Pre-Check Ownership
  const { data: commentCheck } = await supabase
    .from('comments')
    .select('user_id')
    .eq('id', commentId)
    .single();

  if (!commentCheck) {
      throw new Error("Comment not found or you don't have permission to delete it.");
  }

  if (commentCheck.user_id !== currentUserId) {
      throw new Error("Permission denied: You are not the owner of this comment.");
  }

  // 3. Perform Delete
  const executeDelete = async () => {
      return await supabase
        .from('comments')
        .delete({ count: 'exact' })
        .eq('id', commentId);
  };

  let { error, count } = await executeDelete();

  // 4. Retry Logic
  if (error) {
      const isTokenError = error.status === 401 || 
                           (error.message && error.message.includes("JWT"));
      if (isTokenError) {
          const { error: refreshError } = await supabase.auth.refreshSession();
          if (!refreshError) {
              const retry = await executeDelete();
              error = retry.error;
              count = retry.count;
          }
      }
  }

  // 5. Interpret Results
  if (error) {
      if (error.status === 403 || error.code === '42501') {
          throw new Error("Permission denied. You can only delete your own comments.");
      }
      throw new Error(formatError(error));
  }

  if (count === 0) {
      throw new Error("You don't have permission to delete this comment.");
  }
};

const cleanUpOldPosts = async (client: SupabaseClient) => {
  try {
    const { count } = await client.from('posts').select('*', { count: 'exact', head: true });

    if (count !== null && count > MAX_POSTS_LIMIT) {
      const excess = count - MAX_POSTS_LIMIT;
      const { data: oldPosts } = await client
        .from('posts')
        .select('id')
        .order('created_at', { ascending: true })
        .limit(excess + 5); 

      if (oldPosts && oldPosts.length > 0) {
        const ids = oldPosts.map(p => p.id);
        await client.from('posts').delete().in('id', ids);
      }
    }
  } catch (e) {
    // Ignore cleanup errors
  }
};

export const toggleLike = async (postId: string, increment: boolean) => {
  if (!postId) return;
  try {
    const { data } = await supabase.from('posts').select('likes').eq('id', postId).single();
    if (data) {
      const newLikes = Math.max(0, data.likes + (increment ? 1 : -1));
      await supabase.from('posts').update({ likes: newLikes }).eq('id', postId);
    }
  } catch (e) {
    console.error("[Echo] Like failed:", formatError(e));
  }
};

export const subscribeToPosts = (callback: (payload: any) => void) => {
  return supabase
    .channel('public:posts_and_comments')
    .on('postgres_changes', { event: '*', schema: 'public', table: 'posts' }, callback)
    .on('postgres_changes', { event: '*', schema: 'public', table: 'comments' }, callback)
    .subscribe();
};

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Sun, Moon, Database, XCircle, Terminal, Check, Hash, X, Info, Sparkles, AtSign, Loader2, ArrowDown } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { Post } from './types';
import * as SupabaseService from './services/supabaseClient';

type FilterState = { type: 'tag' | 'user'; value: string } | null;

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);

  const [currentUserNickname, setCurrentUserNickname] = useState<string>(() => {
    if (typeof window !== 'undefined') {
        return localStorage.getItem('echo_nickname') || 'Guest';
    }
    return 'Guest';
  });

  const [authUserId, setAuthUserId] = useState<string | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [copied, setCopied] = useState(false);

  const [activeFilter, setActiveFilter] = useState<FilterState>(null);

  const [showDebug, setShowDebug] = useState(false);

  // Pull-to-Refresh State
  const [pullDistance, setPullDistance] = useState(0);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const touchStartRef = useRef(0);
  const isDraggingRef = useRef(false);
  const currentPullYRef = useRef(0);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      return saved === 'light' || saved === 'dark' ? saved : 'light';
    }
    return 'light';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('echo_nickname', currentUserNickname);
  }, [currentUserNickname]);

  // Init Auth and Load Data
  useEffect(() => {
    const init = async () => {
        try {
            setIsAuthLoading(true);
            const uid = await SupabaseService.initializeAuth();
            setAuthUserId(uid);
            await loadPosts();
        } catch (e: any) {
            console.error("Critical Init Failure", e);
            setErrorMsg(getErrorMessage(e));
        } finally {
            setIsAuthLoading(false);
            setIsLoading(false);
        }
    };
    init();
  }, []);

  const getErrorMessage = (e: any) => {
    if (!e) return "Unknown error";
    if (e.code && e.message) return `Error ${e.code}: ${e.message}`;
    if (e.message) return e.message;
    if (typeof e === 'object') return JSON.stringify(e);
    return String(e);
  };

  const loadPosts = useCallback(async () => {
    try {
      const remotePosts = await SupabaseService.fetchPosts();
      setPosts(remotePosts);
    } catch (e: any) {
      console.error("Failed to load posts", e);
      if (posts.length === 0) {
        const msg = getErrorMessage(e);
        setErrorMsg(msg);
        if (msg.includes("column") && msg.includes("does not exist")) {
            setShowDebug(true);
        }
      }
    }
  }, [posts.length]);

  // Pull to Refresh Logic
  const loadPostsRef = useRef(loadPosts);
  useEffect(() => { loadPostsRef.current = loadPosts; }, [loadPosts]);

  useEffect(() => {
    const handleTouchStart = (e: TouchEvent) => {
        // Only start if we are at the top and not already refreshing
        if (window.scrollY <= 0 && !isRefreshing) {
            touchStartRef.current = e.touches[0].clientY;
            isDraggingRef.current = true;
        }
    };

    const handleTouchMove = (e: TouchEvent) => {
        if (!isDraggingRef.current || isRefreshing) return;

        const currentY = e.touches[0].clientY;
        const diff = currentY - touchStartRef.current;

        // If dragging up or page is scrolled, cancel
        if (diff < 0 || window.scrollY > 0) {
            isDraggingRef.current = false;
            setPullDistance(0);
            return;
        }

        if (diff > 0) {
            if (e.cancelable) e.preventDefault();

            // Material Design 3 style logarithmic damping
            // Allows the pull to feel "heavy" as you pull further down
            const limit = 180; // Maximum pixels the content can move
            const dampFactor = 0.5;
            // Damping formula: result = limit * (1 - e^(-diff / (limit * 2))) ? 
            // Simplified Logarithmic:
            const damped = Math.min(Math.pow(diff, 0.8), limit);

            currentPullYRef.current = damped;
            setPullDistance(damped);
        }
    };

    const handleTouchEnd = async () => {
        if (!isDraggingRef.current || isRefreshing) return;
        isDraggingRef.current = false;

        const triggerThreshold = 80; // Distance needed to trigger refresh

        if (currentPullYRef.current > triggerThreshold) {
            setIsRefreshing(true);
            setPullDistance(triggerThreshold); // Snap to threshold

            // Haptic
            if (typeof navigator !== 'undefined' && navigator.vibrate) {
                navigator.vibrate(10);
            }

            try {
                const startTime = Date.now();
                await loadPostsRef.current();
                const elapsed = Date.now() - startTime;
                // Ensure spinner shows for at least 600ms for visual feedback
                if (elapsed < 600) {
                    await new Promise(r => setTimeout(r, 600 - elapsed));
                }
            } finally {
                setIsRefreshing(false);
                setPullDistance(0);
                currentPullYRef.current = 0;
            }
        } else {
            // Snap back without refreshing
            setPullDistance(0);
            currentPullYRef.current = 0;
        }
    };

    // Use active listeners to preventDefault properly
    document.addEventListener('touchstart', handleTouchStart, { passive: true });
    document.addEventListener('touchmove', handleTouchMove, { passive: false });
    document.addEventListener('touchend', handleTouchEnd, { passive: true });

    return () => {
        document.removeEventListener('touchstart', handleTouchStart);
        document.removeEventListener('touchmove', handleTouchMove);
        document.removeEventListener('touchend', handleTouchEnd);
    };
  }, [isRefreshing]);

  useEffect(() => {
    const subscription = SupabaseService.subscribeToPosts((payload) => {
      if (payload.eventType === 'INSERT' || payload.eventType === 'DELETE') {
        loadPosts();
      }
    });
    return () => { subscription?.unsubscribe(); };
  }, [loadPosts]);

  const handleUserPost = async (nickname: string, content: string, tags: string[]) => {
    if (!authUserId) return;
    setCurrentUserNickname(nickname);

    const tempId = Date.now().toString(); 
    const tempPost: Post = {
        id: tempId,
        author: { 
            nickname, 
            avatarSeed: nickname, 
            isAi: false,
            userId: authUserId
        },
        content,
        tags,
        timestamp: Date.now(),
        likes: 0,
        comments: []
    };

    setPosts(prev => [tempPost, ...prev]);

    try {
        const realPost = await SupabaseService.createPost(nickname, content, tags);
        if (realPost) {
            setPosts(prev => prev.map(p => p.id === tempId ? realPost : p));
        }
    } catch (e: any) {
        console.error("Post failed", e);
        setPosts(prev => prev.filter(p => p.id !== tempId)); 
        alert(`Failed to post.\n\n${getErrorMessage(e)}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
    // 1. Snapshot for rollback
    const snapshot = [...posts];

    // 2. Optimistic Update
    setPosts(prev => prev.filter(p => p.id !== postId));

    // Ignore temp posts (no hyphen, only digits - usually local only)
    if (!postId.includes('-') && /^\d+$/.test(postId)) return;

    try {
        const client = SupabaseService.getSupabase();
        const result = await SupabaseService.deletePost(client, postId, authUserId);

        if (!result.success) {
            // Rollback if failed
            setPosts(snapshot);

            // Detailed handling based on reason
            if (result.reason === 'not_owner') {
                alert(result.error?.message || "You cannot delete this post.");
            } else if (result.reason === 'not_found') {
                // If it's already gone, we probably shouldn't have rolled back, but per the pattern
                // we restore snapshot and let the next refresh sync it, or we alert the user.
                // However, logically if it's 'not_found', the optimistic delete was correct.
                // But since we just rolled back above:
                alert("Post already deleted or not found.");
                // Optional: Force reload to sync state
                loadPosts();
            } else {
                alert(result.error?.message || "Failed to delete post.");
            }
        }
    } catch (e: any) {
        // Unexpected crash
        setPosts(snapshot);
        console.error("Delete exception", e);
