/**
 * deletePost - Service layer function to delete a post safely with ownership pre-check.
 * @param supabase - SupabaseClient (from @supabase/supabase-js) bound to the user's session
 * @param postId - id of the post to delete
 * @param currentUserId - the currently-authenticated user's id (string) OR null for guest
 */
export async function deletePost(
  supabase: SupabaseClient,
  postId: string,
  currentUserId: string | null
): Promise<DeleteResult> {
  try {
    // 1) Fetch the post user_id to check ownership
    const { data: rows, error: fetchErr } = await supabase
      .from('posts')
      .select('id, user_id, nickname, content')
      .eq('id', postId)
      .limit(1)
      .maybeSingle();

    if (fetchErr) {
      // Network or permission to read failed
      return {
        success: false,
        error: { message: fetchErr.message, status: fetchErr.status },
        reason: fetchErr.status === 403 ? 'permission' : 'network',
      };
    }

    if (!rows) {
      return { success: false, error: { message: 'Post not found' }, reason: 'not_found' };
    }

    const postUserId: string | null = rows.user_id ?? null;

    // 2) Resolve caller identity - currentUserId should come from your app's auth wrapper
    // If you allow shadow/guest users, your app should supply the shadow id as currentUserId.
    if (!currentUserId) {
      return {
        success: false,
        error: { message: 'Not authenticated' },
        reason: 'not_owner',
      };
    }

    // 3) Ownership check
    if (postUserId !== currentUserId) {
      return {
        success: false,
        error: { message: 'You are not the owner of this post' },
        reason: 'not_owner',
      };
    }

    // 4) Attempt the delete
    const { data: deleted, error: deleteErr } = await supabase
      .from('posts')
      .delete()
      .eq('id', postId)
      .select()
      .maybeSingle();

    if (deleteErr) {
      // Final safeguard: RLS could deny this even if pre-check passed (race conditions)
      return {
        success: false,
        error: { message: deleteErr.message, status: deleteErr.status },
        reason: deleteErr.status === 403 ? 'permission' : 'network',
      };
    }

    return { success: true, deleted: deleted ?? null };
  } catch (err: any) {
