export const createComment = async (postId: string, content: string, nickname: string, userId: string): Promise<Comment> => {
  if (!validateUUID(postId)) console.warn("Potential Invalid UUID for comment parent", postId);

  if (!content || content.trim().length === 0) throw new Error("Comment cannot be empty");
  if (content.length > 2000) throw new Error("Comment exceeds 2000 characters");
  if (!userId) throw new Error("Fatal: User ID is missing for comment creation.");

  try {
    const { data, error } = await supabase
      .from('comments')
      .insert([{
        post_id: postId,
        content: content,
        body: content,
        nickname,
        avatar_seed: nickname,
        user_id: userId
      }])
      .select()
      .single();

    if (error) throw error;

    return mapRowToComment(data);
  } catch (error) {
    console.error("[Echo] Create Comment Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

export const deleteComment = async (commentId: string): Promise<void> => {
  if (!commentId) throw new Error("Invalid Comment ID");

  // 1. Resolve Identity
  const { data: { session }, error: sessionError } = await supabase.auth.getSession();

  if (sessionError || !session?.user) {
      if (isUsingShadowMode) {
          throw new Error("Guest users cannot delete comments. Please sign in.");
      }
      throw new Error("Authentication required to delete comments.");
  }

  const currentUserId = session.user.id;

  // 2. Pre-Check Ownership
  const { data: commentCheck } = await supabase
    .from('comments')
    .select('user_id')
    .eq('id', commentId)
    .single();

  if (!commentCheck) {
      throw new Error("Comment not found or you don't have permission to delete it.");
  }

  if (commentCheck.user_id !== currentUserId) {
      throw new Error("Permission denied: You are not the owner of this comment.");
  }

  // 3. Perform Delete
  const executeDelete = async () => {
      return await supabase
        .from('comments')
        .delete({ count: 'exact' })
        .eq('id', commentId);
  };

  let { error, count } = await executeDelete();

  // 4. Retry Logic
  if (error) {
      const isTokenError = error.status === 401 || 
                           (error.message && error.message.includes("JWT"));
      if (isTokenError) {
          const { error: refreshError } = await supabase.auth.refreshSession();
          if (!refreshError) {
              const retry = await executeDelete();
              error = retry.error;
              count = retry.count;
          }
      }
  }

  // 5. Interpret Results
  if (error) {
      if (error.status === 403 || error.code === '42501') {
          throw new Error("Permission denied. You can only delete your own comments.");
      }
      throw new Error(formatError(error));
  }

  if (count === 0) {
      throw new Error("You don't have permission to delete this comment.");
  }
};

const cleanUpOldPosts = async (client: SupabaseClient) => {
  try {
    const { count } = await client.from('posts').select('*', { count: 'exact', head: true });

    if (count !== null && count > MAX_POSTS_LIMIT) {
      const excess = count - MAX_POSTS_LIMIT;
      const { data: oldPosts } = await client
        .from('posts')
        .select('id')
        .order('created_at', { ascending: true })
        .limit(excess + 5); 

      if (oldPosts && oldPosts.length > 0) {
        const ids = oldPosts.map(p => p.id);
        await client.from('posts').delete().in('id', ids);
      }
    }
  } catch (e) {
    // Ignore cleanup errors
  }
};

export const toggleLike = async (postId: string, increment: boolean) => {
  if (!postId) return;
  try {
    const { data } = await supabase.from('posts').select('likes').eq('id', postId).single();
    if (data) {
      const newLikes = Math.max(0, data.likes + (increment ? 1 : -1));
      await supabase.from('posts').update({ likes: newLikes }).eq('id', postId);
    }
  } catch (e) {
    console.error("[Echo] Like failed:", formatError(e));
  }
};

export const subscribeToPosts = (callback: (payload: any) => void) => {
  return supabase
    .channel('public:posts_and_comments')
    .on('postgres_changes', { event: '*', schema: 'public', table: 'posts' }, callback)
    .on('postgres_changes', { event: '*', schema: 'public', table: 'comments' }, callback)
    .subscribe();
};

import React, { useState, useEffect, useRef } from 'react';
import { Heart, MessageCircle, MoreVertical, Trash2, Send, X, ChevronDown, ChevronUp, AtSign } from 'lucide-react';
import { Post, Comment } from '../types';
import { DEFAULT_AVATAR_URL } from '../constants';
import { toggleLike, createComment, deleteComment } from '../services/supabaseClient';

interface PostCardProps {
  post: Post;
  isUser: boolean;
  currentUserId: string | null;
  onDelete?: (id: string) => void;
  onTagClick?: (tag: string) => void;
  onUserClick?: (nickname: string) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ post, isUser, onDelete, onTagClick, onUserClick, currentUserId }) => {
  const [liked, setLiked] = useState(false);
  const [optimisticLikes, setOptimisticLikes] = useState(post.likes);

  // Comment State
  const [showComments, setShowComments] = useState(false);
  const [comments, setComments] = useState<Comment[]>(post.comments || []);
  const [newCommentText, setNewCommentText] = useState('');
  const [isSubmittingComment, setIsSubmittingComment] = useState(false);

  // Mention State
  const [mentionQuery, setMentionQuery] = useState<string | null>(null);
  const [mentionIndex, setMentionIndex] = useState<number>(-1); // Where the @ started
  const inputRef = useRef<HTMLInputElement>(null);

  // Sync props to state if post updates from parent (real-time)
  useEffect(() => {
    setComments(post.comments || []);
  }, [post.comments]);

  const handleLike = () => {
    const isLiking = !liked;
    setLiked(isLiking);
    setOptimisticLikes(prev => isLiking ? prev + 1 : prev - 1);
    toggleLike(post.id, isLiking);
  };

  const handleDelete = () => {
    if (confirm('Are you sure you want to delete this post?') && onDelete) {
      onDelete(post.id);
    }
  };

  const handleTagClick = (tag: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (onTagClick) onTagClick(tag);
  };

  const handleUserClick = (e: React.MouseEvent, nickname?: string) => {
    e.stopPropagation();
    if (onUserClick) onUserClick(nickname || post.author.nickname);
  }

  const toggleComments = () => {
    setShowComments(!showComments);
  };

  // --- MENTION LOGIC START ---

  // Get unique participants in this thread for suggestions
  const getThreadParticipants = () => {
    const participants = new Set<string>();
    // Add Post Author
    participants.add(post.author.nickname);
    // Add Commenters
    comments.forEach(c => participants.add(c.author.nickname));

    // Convert to array and filter by query
    const all = Array.from(participants);
    if (!mentionQuery) return all;
    return all.filter(name => name.toLowerCase().startsWith(mentionQuery.toLowerCase()));
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setNewCommentText(value);

    // Regex to find the last @word being typed. 
    // Captures group 1 as the name after @
    const match = value.match(/@(\w*)$/);

    if (match) {
      setMentionQuery(match[1]);
      setMentionIndex(match.index!);
    } else {
      setMentionQuery(null);
      setMentionIndex(-1);
    }
  };

  const insertMention = (nickname: string) => {
    if (mentionIndex === -1) return;

    // Replace the @query with @nickname + space
    const before = newCommentText.substring(0, mentionIndex);
    // We don't use 'after' because we assume cursor is at end for this simple logic
    // but correct logic handles cursor position. For simplicity:
    const newValue = before + `@${nickname} `;

    setNewCommentText(newValue);
    setMentionQuery(null);
    setMentionIndex(-1);

    // Refocus
    if (inputRef.current) {
      inputRef.current.focus();
    }
  };

  // Render text with clickable @mentions
  const renderContentWithMentions = (content: string) => {
    // Split by mention pattern: @nickname
    // We allow alphanumeric, underscores, and hyphens in nicknames
    const parts = content.split(/(@[\w-]+)/g);

    return parts.map((part, i) => {
      if (part.startsWith('@') && part.length > 1) {
        const nickname = part.substring(1);
        return (
          <span 
            key={i} 
            onClick={(e) => handleUserClick(e, nickname)}
            className="text-green-600 dark:text-green-400 font-medium cursor-pointer hover:underline bg-green-50 dark:bg-green-900/30 px-0.5 rounded"
          >
            {part}
          </span>
        );
      }
      return <span key={i}>{part}</span>;
    });
  };

  // --- MENTION LOGIC END ---

  const handleSubmitComment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newCommentText.trim()) return;

    if (!currentUserId) {
        alert("You must be signed in (or shadow authenticated) to comment.");
        return;
    }

    const text = newCommentText;
    setNewCommentText(''); // Clear input immediately
    setMentionQuery(null); // Clear mentions
    setIsSubmittingComment(true);

    const nickname = localStorage.getItem('echo_nickname') || 'Guest';

    // Optimistic Comment
    const tempId = 'temp-' + Date.now();
    const optimisticComment: Comment = {
      id: tempId,
      author: {
        nickname,
        avatarSeed: nickname,
        isAi: false,
        userId: currentUserId || ''
      },
      content: text,
      timestamp: Date.now(),
      likes: 0
    };

    setComments(prev => [...prev, optimisticComment]);
    if (!showComments) setShowComments(true);

    try {
      const realComment = await createComment(post.id, text, nickname, currentUserId);
      setComments(prev => prev.map(c => c.id === tempId ? realComment : c));
    } catch (err) {
      console.error("Failed to submit comment", err);
      alert("Failed to post comment. Please try again.");
      setComments(prev => prev.filter(c => c.id !== tempId));
      setNewCommentText(text); 
    } finally {
      setIsSubmittingComment(false);
    }
  };

  const handleDeleteComment = async (commentId: string) => {
    if (!confirm("Delete this comment?")) return;

    const previousComments = [...comments];
    setComments(prev => prev.filter(c => c.id !== commentId));

    try {
      await deleteComment(commentId);
    } catch (err) {
      console.error("Failed to delete comment", err);
      alert("Could not delete comment.");
      setComments(previousComments);
    }
  };

  const formattedTime = new Intl.DateTimeFormat('en-US', {
    hour: 'numeric',
    minute: 'numeric',
  }).format(new Date(post.timestamp));

  return (
    <div className={`
      relative p-5 mb-4 transition-all duration-300
      rounded-[24px] border
      ${isUser 
        ? 'bg-neutral-100 border-neutral-200 text-black dark:bg-[#1A1A1A] dark:border-neutral-700 dark:text-white' 
        : 'bg-white border-neutral-200 text-neutral-800 dark:bg-[#0A0A0A] dark:border-[#1F1F1F] dark:text-neutral-300' 
      }
    `}>
      {/* Header */}
      <div className="flex items-start justify-between mb-4">
        <div 
            onClick={(e) => handleUserClick(e)}
            className="flex items-center gap-4 group cursor-pointer"
        >
          <img 
            src={DEFAULT_AVATAR_URL(post.author.avatarSeed)} 
            alt={post.author.nickname}
            className="w-10 h-10 rounded-full object-cover grayscale opacity-80 group-hover:grayscale-0 group-hover:scale-105 transition-all border border-neutral-200 dark:border-neutral-800" 
          />
          <div>
            <div className="flex items-center gap-2">
              <span className={`text-base font-medium tracking-wide group-hover:underline ${isUser ? 'text-black dark:text-white' : 'text-neutral-900 dark:text-neutral-200'}`}>
                {post.author.nickname}
              </span>
              {post.author.isAi && (
                <span className="text-[10px] px-2 py-0.5 rounded-full bg-black text-white dark:bg-white dark:text-black font-bold tracking-wider">
                  BOT
                </span>
              )}
            </div>
            <span className="text-xs text-neutral-500 dark:text-neutral-500">{formattedTime}</span>
          </div>
        </div>

        {isUser && (
           <button 
             onClick={handleDelete}
             className="text-neutral-400 hover:text-red-600 dark:text-neutral-500 dark:hover:text-red-400 rounded-full p-2 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
             title="Delete Post"
           >
             <Trash2 size={18} />
           </button>
        )}
      </div>

      {/* Content */}
      <div className="mb-4 pl-[56px]">
