export const createComment = async (postId: string, content: string, nickname: string, userId: string): Promise<Comment> => {
  if (!validateUUID(postId)) console.warn("Potential Invalid UUID for comment parent", postId);

  if (!content || content.trim().length === 0) throw new Error("Comment cannot be empty");
  // Safety check bumped to 5000 chars for comments too
  if (content.length > 5000) throw new Error("Comment exceeds 5000 characters");
  if (!userId) throw new Error("Fatal: User ID is missing for comment creation.");

  try {
    const { data, error } = await supabase
      .from('comments')
      .insert([{
        post_id: postId,
        content: content,
        body: content,
        nickname,
        avatar_seed: nickname,
        user_id: userId
      }])
      .select()
      .single();

    if (error) throw error;

    return mapRowToComment(data);
  } catch (error) {
    console.error("[Echo] Create Comment Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

export const deleteComment = async (commentId: string): Promise<void> => {
  if (!commentId) throw new Error("Invalid Comment ID");

  // 1. Resolve Identity
  const { data: { session }, error: sessionError } = await supabase.auth.getSession();

  if (sessionError || !session?.user) {
      if (isUsingShadowMode) {
          throw new Error("Guest users cannot delete comments. Please sign in.");
      }
      throw new Error("Authentication required to delete comments.");
  }

  const currentUserId = session.user.id;

  // 2. Pre-Check Ownership
  const { data: commentCheck } = await supabase
    .from('comments')
    .select('user_id')
    .eq('id', commentId)
    .single();

  if (!commentCheck) {
      throw new Error("Comment not found or you don't have permission to delete it.");
  }

  if (commentCheck.user_id !== currentUserId) {
      throw new Error("Permission denied: You are not the owner of this comment.");
  }

  // 3. Perform Delete
  const executeDelete = async () => {
      return await supabase
        .from('comments')
        .delete({ count: 'exact' })
        .eq('id', commentId);
  };

  let { error, count } = await executeDelete();

  // 4. Retry Logic
  if (error) {
      const isTokenError = error.status === 401 || 
                           (error.message && error.message.includes("JWT"));
      if (isTokenError) {
          const { error: refreshError } = await supabase.auth.refreshSession();
          if (!refreshError) {
              const retry = await executeDelete();
              error = retry.error;
              count = retry.count;
          }
      }
  }

  // 5. Interpret Results
  if (error) {
      if (error.status === 403 || error.code === '42501') {
          throw new Error("Permission denied. You can only delete your own comments.");
      }
      throw new Error(formatError(error));
  }

  if (count === 0) {
      throw new Error("You don't have permission to delete this comment.");
  }
};

const cleanUpOldPosts = async (client: SupabaseClient) => {
  try {
    const { count } = await client.from('posts').select('*', { count: 'exact', head: true });

    if (count !== null && count > MAX_POSTS_LIMIT) {
      const excess = count - MAX_POSTS_LIMIT;
      const { data: oldPosts } = await client
        .from('posts')
        .select('id')
        .order('created_at', { ascending: true })
        .limit(excess + 5); 

      if (oldPosts && oldPosts.length > 0) {
        const ids = oldPosts.map(p => p.id);
        await client.from('posts').delete().in('id', ids);
      }
    }
  } catch (e) {
    // Ignore cleanup errors
  }
};

export const toggleLike = async (postId: string, increment: boolean) => {
  if (!postId) return;
  try {
    const { data } = await supabase.from('posts').select('likes').eq('id', postId).single();
    if (data) {
      const newLikes = Math.max(0, data.likes + (increment ? 1 : -1));
      await supabase.from('posts').update({ likes: newLikes }).eq('id', postId);
    }
  } catch (e) {
    console.error("[Echo] Like failed:", formatError(e));
  }
};

export const subscribeToPosts = (callback: (payload: any) => void) => {
  return supabase
    .channel('public:posts_and_comments')
    .on('postgres_changes', { event: '*', schema: 'public', table: 'posts' }, callback)
    .on('postgres_changes', { event: '*', schema: 'public', table: 'comments' }, callback)
    .subscribe();
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Hash, AtSign, X } from 'lucide-react';
import { DEFAULT_AVATAR_URL } from '../constants';

interface CreatePostProps {
  onPost: (nickname: string, content: string, tags: string[]) => void;
  defaultNickname: string;
}

export const CreatePost: React.FC<CreatePostProps> = ({ onPost, defaultNickname }) => {
  const [nickname, setNickname] = useState(defaultNickname);
  const [content, setContent] = useState('');
  const [tags, setTags] = useState<string[]>([]);
  const [tagInput, setTagInput] = useState('');
  const [isFocused, setIsFocused] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // CHARACTER LIMIT CONFIGURATION
  const MAX_CHARS = 800;

  const charCount = content.length;
  // We force the content to never exceed MAX_CHARS, so this is mainly for full-circle logic
  const isAtLimit = charCount >= MAX_CHARS;
  const remaining = Math.max(0, MAX_CHARS - charCount);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = textareaRef.current.scrollHeight + 'px';
    }
  }, [content]);

  const handleContentChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const val = e.target.value;
    // Strict enforcement
    if (val.length <= MAX_CHARS) {
        setContent(val);
    } else {
        // Handle paste overflow
        setContent(val.slice(0, MAX_CHARS));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!nickname.trim() || !content.trim()) return;

    // Merge explicit tags with hashtags in content
    const contentHashtags = content.match(/#[\w]+/g)?.map(t => t.replace('#', '')) || [];

    // Process current tag input if any exists but wasn't "entered"
    let currentInputTags: string[] = [];
    if (tagInput.trim()) {
       currentInputTags = tagInput.split(/[\s,]+/).map(t => t.trim().replace(/^#/, '')).filter(Boolean);
    }

    const finalTags = [...new Set([...tags, ...currentInputTags, ...contentHashtags])];

    onPost(nickname, content, finalTags);

    // Reset
    setContent('');
    setTags([]);
    setTagInput('');
    setIsFocused(false);
    if (textareaRef.current) textareaRef.current.style.height = 'auto';
  };

  const handleTagKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (['Enter', ' ', ','].includes(e.key)) {
      e.preventDefault();
      const newTags = tagInput.split(/[\s,]+/).map(t => t.trim().replace(/^#/, '')).filter(t => t.length > 0);
      if (newTags.length > 0) {
        setTags(prev => [...new Set([...prev, ...newTags])]); // No duplicates in chip list
        setTagInput('');
      }
    } else if (e.key === 'Backspace' && tagInput === '' && tags.length > 0) {
      setTags(prev => prev.slice(0, -1));
    }
  };

  const removeTag = (tagToRemove: string) => {
    setTags(prev => prev.filter(t => t !== tagToRemove));
  };

  const handleFocus = () => setIsFocused(true);

  // Handle outside click to collapse if empty
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        if (!content.trim() && tags.length === 0 && !tagInput.trim()) {
           setIsFocused(false);
        }
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [content, tags, tagInput]);

  const isExpanded = isFocused || content.length > 0 || tags.length > 0 || tagInput.length > 0;

  // Circular Progress Calculation based on CHARACTERS
  const radius = 10;
  const circumference = 2 * Math.PI * radius;
  const progressPercentage = Math.min(100, (charCount / MAX_CHARS) * 100);
  const strokeDashoffset = circumference - (progressPercentage / 100) * circumference;

  const progressColor = isAtLimit 
    ? 'text-red-500' 
    : charCount > MAX_CHARS * 0.9 
        ? 'text-yellow-500' 
        : 'text-green-500';

  return (
    <div 
        ref={containerRef}
        className={`
            relative transition-all duration-300 ease-out
            bg-white dark:bg-[#0F0F0F] 
            rounded-[28px] 
            ${isExpanded 
                ? 'shadow-xl shadow-black/5 ring-1 ring-black/5 dark:shadow-white/5 dark:ring-white/10 p-6 mb-8' 
                : 'shadow-sm border border-neutral-200 dark:border-neutral-800 p-4 mb-6 hover:border-neutral-300 dark:hover:border-neutral-700'
            }
        `}
    >
        {/* Header: Identity */}
        <div className={`flex items-center gap-3 mb-4 transition-all duration-300 ${isExpanded ? 'opacity-100' : 'opacity-80'}`}>
            <div className="relative">
                <img 
                    src={DEFAULT_AVATAR_URL(nickname || 'Guest')} 
                    alt="Avatar"
                    className="w-10 h-10 rounded-full border border-neutral-100 dark:border-neutral-800 bg-neutral-50 dark:bg-neutral-900 object-cover"
                />
                <div className="absolute -bottom-1 -right-1 bg-black dark:bg-white text-white dark:text-black rounded-full p-1 border-2 border-white dark:border-black">
                   <AtSign size={10} />
                </div>
            </div>

            <div className="flex flex-col w-full">
                <span className="text-[10px] font-bold text-neutral-400 uppercase tracking-wider mb-0.5">Posting as</span>
                <input
                    type="text"
                    value={nickname}
                    onChange={(e) => setNickname(e.target.value)}
                    onFocus={handleFocus}
                    placeholder="Anonymous"
                    className="bg-transparent border-none outline-none p-0 text-sm font-bold text-neutral-900 dark:text-neutral-100 placeholder-neutral-400 w-full"
                />
            </div>
        </div>

        {/* Text Editor */}
        <textarea
            ref={textareaRef}
            dir="auto"
            value={content}
            maxLength={MAX_CHARS}
            onChange={handleContentChange}
            onFocus={handleFocus}
            placeholder="What's on your mind?"
            className={`
                w-full bg-transparent border-none outline-none focus:ring-0 resize-none 
                text-lg leading-relaxed
                text-neutral-900 placeholder-neutral-400
                dark:text-white dark:placeholder-neutral-600
                min-h-[60px] max-h-[400px]
                transition-all duration-200
            `}
        />

        {/* Interactive Tags */}
        {(isExpanded) && (
            <div className="mt-3 flex flex-wrap gap-2 items-center animate-in fade-in slide-in-from-top-2">
                {tags.map(tag => (
                    <span key={tag} className="inline-flex items-center gap-1 px-2.5 py-1 rounded-lg bg-neutral-100 dark:bg-neutral-800 text-neutral-700 dark:text-neutral-300 text-xs font-medium border border-neutral-200 dark:border-neutral-700">
                        #{tag}
                        <button onClick={() => removeTag(tag)} className="hover:text-red-500 rounded-full p-0.5 transition-colors">
                            <X size={12} />
                        </button>
                    </span>
                ))}
                <div className="flex items-center gap-2 flex-1 min-w-[120px]">
                    <Hash size={14} className="text-neutral-400" />
                    <input 
                        type="text"
                        value={tagInput}
                        onChange={(e) => setTagInput(e.target.value)}
                        onKeyDown={handleTagKeyDown}
                        onFocus={handleFocus}
                        placeholder="Add tags..."
                        className="bg-transparent border-none outline-none text-sm text-neutral-600 dark:text-neutral-300 placeholder-neutral-400 flex-1"
                    />
                </div>
            </div>
        )}

        {/* Footer Actions */}
        {(isExpanded) && (
            <div className="flex items-center justify-end mt-5 pt-3 border-t border-neutral-100 dark:border-white/5 animate-in fade-in">
                {/* Submit Area */}
                <div className="flex items-center gap-4">
                    {/* Character Count Indicator */}
                    <div className="relative w-6 h-6 flex items-center justify-center">
                        <svg className="w-full h-full transform -rotate-90">
                            <circle
                                cx="12"
                                cy="12"
                                r={radius}
                                stroke="currentColor"
                                strokeWidth="2"
                                fill="transparent"
                                className="text-neutral-100 dark:text-neutral-800"
                            />
                            <circle
                                cx="12"
                                cy="12"
                                r={radius}
                                stroke="currentColor"
                                strokeWidth="2"
                                fill="transparent"
                                strokeDasharray={circumference}
                                strokeDashoffset={strokeDashoffset}
                                strokeLinecap="round"
                                className={`${progressColor} transition-all duration-300`}
                            />
                        </svg>
                        {/* Show count only when getting close to limit */}
                        {(charCount > MAX_CHARS * 0.8) && (
                            <span className={`absolute text-[8px] font-bold ${isAtLimit ? 'text-red-500' : 'text-neutral-500'}`}>
                                {remaining}
                            </span>
                        )}
                    </div>

                    <button 
                        onClick={handleSubmit}
                        disabled={!content.trim() || !nickname.trim()}
                        className="
                            group flex items-center gap-2 px-5 py-2 rounded-full font-bold text-sm transition-all duration-200
                            bg-black text-white hover:bg-neutral-800 hover:scale-105 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:scale-100
                            dark:bg-white dark:text-black dark:hover:bg-neutral-200
                        "
                    >
                        <span>Post</span>
                        <Send size={16} className="group-hover:translate-x-0.5 transition-transform" />
                    </button>
                </div>
            </div>
        )}
    </div>
  );
};

