        setErrorMsg(msg);
        if (msg.includes("column") && msg.includes("does not exist")) {
            setShowDebug(true);
        }
      }
    }
  }, [posts.length]);

  // Pull to Refresh Logic
  const loadPostsRef = useRef(loadPosts);
  useEffect(() => { loadPostsRef.current = loadPosts; }, [loadPosts]);

  useEffect(() => {
    const handleTouchStart = (e: TouchEvent) => {
        // Only start if we are at the top and not already refreshing
        if (window.scrollY <= 0 && !isRefreshing) {
            touchStartRef.current = e.touches[0].clientY;
            isDraggingRef.current = true;
        }
    };

    const handleTouchMove = (e: TouchEvent) => {
        if (!isDraggingRef.current || isRefreshing) return;

        const currentY = e.touches[0].clientY;
        const diff = currentY - touchStartRef.current;

        // If dragging up or page is scrolled, cancel
        if (diff < 0 || window.scrollY > 0) {
            isDraggingRef.current = false;
            setPullDistance(0);
            return;
        }

        if (diff > 0) {
            if (e.cancelable) e.preventDefault();

            // Material Design 3 style logarithmic damping
            // Allows the pull to feel "heavy" as you pull further down
            const limit = 180; // Maximum pixels the content can move
            const dampFactor = 0.5;
            // Damping formula: result = limit * (1 - e^(-diff / (limit * 2))) ? 
            // Simplified Logarithmic:
            const damped = Math.min(Math.pow(diff, 0.8), limit);

            currentPullYRef.current = damped;
            setPullDistance(damped);
        }
    };

    const handleTouchEnd = async () => {
        if (!isDraggingRef.current || isRefreshing) return;
        isDraggingRef.current = false;

        const triggerThreshold = 80; // Distance needed to trigger refresh

        if (currentPullYRef.current > triggerThreshold) {
            setIsRefreshing(true);
            setPullDistance(triggerThreshold); // Snap to threshold

            // Haptic
            if (typeof navigator !== 'undefined' && navigator.vibrate) {
                navigator.vibrate(10);
            }

            try {
                const startTime = Date.now();
                await loadPostsRef.current();
                const elapsed = Date.now() - startTime;
                // Ensure spinner shows for at least 600ms for visual feedback
                if (elapsed < 600) {
                    await new Promise(r => setTimeout(r, 600 - elapsed));
                }
            } finally {
                setIsRefreshing(false);
                setPullDistance(0);
                currentPullYRef.current = 0;
            }
        } else {
            // Snap back without refreshing
            setPullDistance(0);
            currentPullYRef.current = 0;
        }
    };

    // Use active listeners to preventDefault properly
    document.addEventListener('touchstart', handleTouchStart, { passive: true });
    document.addEventListener('touchmove', handleTouchMove, { passive: false });
    document.addEventListener('touchend', handleTouchEnd, { passive: true });

    return () => {
        document.removeEventListener('touchstart', handleTouchStart);
        document.removeEventListener('touchmove', handleTouchMove);
        document.removeEventListener('touchend', handleTouchEnd);
    };
  }, [isRefreshing]);

  useEffect(() => {
    const subscription = SupabaseService.subscribeToPosts((payload) => {
      if (payload.eventType === 'INSERT' || payload.eventType === 'DELETE') {
