import React, { useState, useEffect, useRef } from 'react';
import { Heart, MessageCircle, MoreVertical, Trash2, Send, X, ChevronDown, ChevronUp, AtSign } from 'lucide-react';
import { Post, Comment } from '../types';
import { DEFAULT_AVATAR_URL } from '../constants';
import { toggleLike, createComment, deleteComment } from '../services/supabaseClient';

interface PostCardProps {
  post: Post;
  isUser: boolean;
  currentUserId: string | null;
  onDelete?: (id: string) => void;
  onTagClick?: (tag: string) => void;
  onUserClick?: (user: { userId: string; nickname: string }) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ post, isUser, onDelete, onTagClick, onUserClick, currentUserId }) => {
  const [liked, setLiked] = useState(false);
  const [optimisticLikes, setOptimisticLikes] = useState(post.likes);

  // Comment State
  const [showComments, setShowComments] = useState(false);
  const [comments, setComments] = useState<Comment[]>(post.comments || []);
  const [newCommentText, setNewCommentText] = useState('');
  const [isSubmittingComment, setIsSubmittingComment] = useState(false);

  // Mention State
  const [mentionQuery, setMentionQuery] = useState<string | null>(null);
  const [mentionIndex, setMentionIndex] = useState<number>(-1); // Where the @ started
  const inputRef = useRef<HTMLInputElement>(null);

  // Sync props to state if post updates from parent (real-time)
  useEffect(() => {
    setComments(post.comments || []);
  }, [post.comments]);

  const handleLike = () => {
    const isLiking = !liked;
    setLiked(isLiking);
    setOptimisticLikes(prev => isLiking ? prev + 1 : prev - 1);
    toggleLike(post.id, isLiking);
  };

  const handleDelete = () => {
    if (confirm('Are you sure you want to delete this post?') && onDelete) {
      onDelete(post.id);
    }
  };

  const handleTagClick = (tag: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (onTagClick) onTagClick(tag);
  };

  const handleUserClick = (e: React.MouseEvent, userOverride?: { userId: string; nickname: string }) => {
    e.stopPropagation();
    if (onUserClick) {
        if (userOverride) {
            onUserClick(userOverride);
        } else {
             // Default to post author
             onUserClick({ 
                 userId: post.author.userId || '', 
                 nickname: post.author.nickname 
             });
        }
    }
  }

  const toggleComments = () => {
    setShowComments(!showComments);
  };

  // --- MENTION LOGIC START ---

  // Get unique participants in this thread for suggestions
  const getThreadParticipants = () => {
    const participants = new Set<string>();
    // Add Post Author
    participants.add(post.author.nickname);
    // Add Commenters
    comments.forEach(c => participants.add(c.author.nickname));

    // Convert to array and filter by query
    const all = Array.from(participants);
    if (!mentionQuery) return all;
    return all.filter(name => name.toLowerCase().startsWith(mentionQuery.toLowerCase()));
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setNewCommentText(value);

    // Regex to find the last @word being typed. 
    // Captures group 1 as the name after @
    const match = value.match(/@(\w*)$/);

    if (match) {
      setMentionQuery(match[1]);
      setMentionIndex(match.index!);
    } else {
      setMentionQuery(null);
      setMentionIndex(-1);
    }
  };

  const insertMention = (nickname: string) => {
    if (mentionIndex === -1) return;

    // Replace the @query with @nickname + space
    const before = newCommentText.substring(0, mentionIndex);
    // We don't use 'after' because we assume cursor is at end for this simple logic
    // but correct logic handles cursor position. For simplicity:
    const newValue = before + `@${nickname} `;

    setNewCommentText(newValue);
    setMentionQuery(null);
    setMentionIndex(-1);

    // Refocus
    if (inputRef.current) {
      inputRef.current.focus();
    }
  };

  // Render text with clickable @mentions
  const renderContentWithMentions = (content: string) => {
    // Split by mention pattern: @nickname
    // We allow alphanumeric, underscores, and hyphens in nicknames
    const parts = content.split(/(@[\w-]+)/g);

    return parts.map((part, i) => {
      if (part.startsWith('@') && part.length > 1) {
        const nickname = part.substring(1);

        // Try to find this user in the thread to get their ID
        // Priority: Post Author -> Commenters
        let matchedUser = null;
        if (post.author.nickname === nickname) matchedUser = post.author;
        else {
            const commentUser = comments.find(c => c.author.nickname === nickname);
            if (commentUser) matchedUser = commentUser.author;
        }

        if (matchedUser && matchedUser.userId) {
             return (
              <span 
                key={i} 
                onClick={(e) => handleUserClick(e, { userId: matchedUser!.userId!, nickname: matchedUser!.nickname })}
                className="text-green-600 dark:text-green-400 font-medium cursor-pointer hover:underline bg-green-50 dark:bg-green-900/30 px-0.5 rounded"
              >
                {part}
              </span>
            );
        }

        // Fallback if ID not found (just style it)
        return (
             <span key={i} className="text-green-600 dark:text-green-400 font-medium opacity-80">{part}</span>
        );
      }
      return <span key={i}>{part}</span>;
    });
  };

  // --- MENTION LOGIC END ---

  const handleSubmitComment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newCommentText.trim()) return;

    if (!currentUserId) {
        alert("You must be signed in (or shadow authenticated) to comment.");
        return;
    }

    const text = newCommentText;
    setNewCommentText(''); // Clear input immediately
    setMentionQuery(null); // Clear mentions
    setIsSubmittingComment(true);

    const nickname = localStorage.getItem('echo_nickname') || 'Guest';

    // Optimistic Comment
    const tempId = 'temp-' + Date.now();
    const optimisticComment: Comment = {
      id: tempId,
      author: {
        nickname,
        avatarSeed: nickname,
        isAi: false,
        userId: currentUserId || ''
      },
      content: text,
      timestamp: Date.now(),
      likes: 0
    };

    setComments(prev => [...prev, optimisticComment]);
    if (!showComments) setShowComments(true);

    try {
      const realComment = await createComment(post.id, text, nickname, currentUserId);
      setComments(prev => prev.map(c => c.id === tempId ? realComment : c));
    } catch (err) {
      console.error("Failed to submit comment", err);
      alert("Failed to post comment. Please try again.");
      setComments(prev => prev.filter(c => c.id !== tempId));
      setNewCommentText(text); 
    } finally {
      setIsSubmittingComment(false);
    }
  };

  const handleDeleteComment = async (commentId: string) => {
    if (!confirm("Delete this comment?")) return;

    const previousComments = [...comments];
    setComments(prev => prev.filter(c => c.id !== commentId));

    try {
      await deleteComment(commentId);
    } catch (err) {
      console.error("Failed to delete comment", err);
      alert("Could not delete comment.");
      setComments(previousComments);
    }
  };

  const formattedTime = new Intl.DateTimeFormat('en-US', {
    hour: 'numeric',
    minute: 'numeric',
  }).format(new Date(post.timestamp));

  return (
    <div className={`
      relative p-5 mb-4 transition-all duration-300
      rounded-[24px] border
      ${isUser 
        ? 'bg-neutral-100 border-neutral-200 text-black dark:bg-[#1A1A1A] dark:border-neutral-700 dark:text-white' 
        : 'bg-white border-neutral-200 text-neutral-800 dark:bg-[#0A0A0A] dark:border-[#1F1F1F] dark:text-neutral-300' 
      }
    `}>
      {/* Header */}
      <div className="flex items-start justify-between mb-4">
        <div 
            onClick={(e) => handleUserClick(e)}
            className="flex items-center gap-4 group cursor-pointer"
        >
          <img 
            src={DEFAULT_AVATAR_URL(post.author.avatarSeed)} 
            alt={post.author.nickname}
            className="w-10 h-10 rounded-full object-cover grayscale opacity-80 group-hover:grayscale-0 group-hover:scale-105 transition-all border border-neutral-200 dark:border-neutral-800" 
          />
          <div>
            <div className="flex items-center gap-2">
              <span className={`text-base font-medium tracking-wide group-hover:underline ${isUser ? 'text-black dark:text-white' : 'text-neutral-900 dark:text-neutral-200'}`}>
                {post.author.nickname}
              </span>
              {post.author.isAi && (
                <span className="text-[10px] px-2 py-0.5 rounded-full bg-black text-white dark:bg-white dark:text-black font-bold tracking-wider">
                  BOT
                </span>
              )}
            </div>
            <span className="text-xs text-neutral-500 dark:text-neutral-500">{formattedTime}</span>
          </div>
        </div>

        {isUser && (
           <button 
             onClick={handleDelete}
             className="text-neutral-400 hover:text-red-600 dark:text-neutral-500 dark:hover:text-red-400 rounded-full p-2 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
             title="Delete Post"
           >
             <Trash2 size={18} />
           </button>
        )}
      </div>

      {/* Content */}
      <div className="mb-4 pl-[56px]">
        <p 
            dir="auto" 
            className="text-base leading-relaxed tracking-wide opacity-90 text-neutral-800 dark:text-neutral-200 whitespace-pre-wrap"
        >
          {post.content}
        </p>
        {post.tags.length > 0 && (
          <div className="flex flex-wrap gap-2 mt-4">
            {post.tags.map(tag => (
              <span 
                key={tag} 
                onClick={(e) => handleTagClick(tag, e)}
                className="px-3 py-1 rounded-lg text-xs font-medium transition-colors cursor-pointer
                           bg-neutral-100 border border-neutral-200 text-neutral-600 hover:bg-neutral-200 hover:text-black hover:border-neutral-300
                           dark:bg-neutral-900 dark:border-neutral-800 dark:text-neutral-400 dark:hover:text-white dark:hover:border-neutral-600"
              >
                #{tag.replace(/^#/, '')}
              </span>
            ))}
          </div>
        )}
      </div>

      {/* Actions */}
      <div className="flex items-center gap-6 pl-[56px] pt-1">
        <button 
          onClick={handleLike}
          className={`group flex items-center gap-2 text-sm font-medium transition-colors 
            ${liked 
              ? 'text-black dark:text-white' 
              : 'text-neutral-500 hover:text-black dark:text-neutral-500 dark:hover:text-neutral-300'
            }`}
        >
          <div className={`p-2 rounded-full group-hover:bg-black/5 dark:group-hover:bg-white/10 transition-colors`}>
             <Heart size={20} fill={liked ? "currentColor" : "none"} className={liked ? "scale-110" : ""} />
          </div>
          <span>{optimisticLikes}</span>
        </button>

        <button 
          onClick={toggleComments}
          className={`group flex items-center gap-1.5 text-sm font-medium transition-colors
            ${showComments ? 'text-black dark:text-white' : 'text-neutral-500 hover:text-black dark:text-neutral-500 dark:hover:text-white'}
          `}
        >
          <div className="p-2 rounded-full group-hover:bg-black/5 dark:group-hover:bg-white/10 transition-colors">
             <MessageCircle size={20} />
          </div>
          <span>{comments.length}</span>
          <div className="ml-1 opacity-50 group-hover:opacity-100 transition-opacity">
             {showComments ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
          </div>
        </button>
      </div>

      {/* Comments Section */}
      {showComments && (
        <div className="mt-4 pt-4 pl-[56px] border-t border-neutral-100 dark:border-neutral-800 animate-in fade-in slide-in-from-top-2 duration-200">

          {/* Add Comment Input */}
          <form onSubmit={handleSubmitComment} className="flex gap-3 mb-6 relative z-10">
             <img 
                src={DEFAULT_AVATAR_URL(localStorage.getItem('echo_nickname') || 'Guest')} 
                className="w-8 h-8 rounded-full grayscale opacity-50 shrink-0"
             />
             <div className="flex-1 relative">

                {/* Mention Suggestion List */}
                {mentionQuery !== null && (
                    <div className="absolute bottom-full mb-2 left-0 w-full max-h-40 overflow-y-auto bg-white dark:bg-[#1A1A1A] border border-neutral-200 dark:border-neutral-700 rounded-xl shadow-xl z-20 animate-in zoom-in-95 duration-100">
                        {getThreadParticipants().length > 0 ? (
                            getThreadParticipants().map((participant, idx) => (
                                <button
                                    type="button"
                                    key={idx}
                                    onClick={() => insertMention(participant)}
                                    className="w-full text-left px-4 py-2.5 text-sm hover:bg-neutral-100 dark:hover:bg-neutral-800 flex items-center gap-2"
                                >
                                    <div className="w-5 h-5 rounded-full bg-neutral-200 dark:bg-neutral-700 overflow-hidden">
                                         <img src={DEFAULT_AVATAR_URL(participant)} className="w-full h-full object-cover grayscale" />
                                    </div>
                                    <span className="font-medium text-neutral-800 dark:text-neutral-200">{participant}</span>
                                    {participant === post.author.nickname && (
                                        <span className="text-[10px] bg-neutral-200 dark:bg-neutral-700 px-1.5 rounded text-neutral-500">OP</span>
                                    )}
                                </button>
                            ))
                        ) : (
                             <div className="px-4 py-2 text-xs text-neutral-400 italic">No matching users in thread</div>
                        )}
                    </div>
                )}

                <input 
                  ref={inputRef}
                  type="text"
                  dir="auto" 
                  value={newCommentText}
                  onChange={handleInputChange}
                  placeholder="Write a reply... (Type @ to tag)"
                  className="w-full bg-neutral-50 dark:bg-neutral-900 border border-neutral-200 dark:border-neutral-800 rounded-full py-2 px-4 text-sm focus:outline-none focus:border-black dark:focus:border-white transition-colors"
                  autoComplete="off"
                />
                <button 
                  type="submit" 
                  disabled={!newCommentText.trim() || isSubmittingComment}
                  className="absolute right-2 top-1.5 p-1 rounded-full text-black dark:text-white hover:bg-neutral-200 dark:hover:bg-neutral-700 disabled:opacity-30 disabled:hover:bg-transparent transition-all"
                >
                  <Send size={14} />
                </button>
             </div>
          </form>

          {/* Comment List */}
          <div className="space-y-5">
            {comments.map(comment => (
              <div key={comment.id} className="flex gap-3 group/comment">
                <img 
                  src={DEFAULT_AVATAR_URL(comment.author.avatarSeed)} 
                  alt={comment.author.nickname}
                  className="w-8 h-8 rounded-full grayscale opacity-70 shrink-0"
                />
                <div className="flex-1">
                  <div className="flex items-center justify-between">
                    <div 
                        className="flex items-center gap-2 mb-0.5 cursor-pointer hover:underline"
                        onClick={(e) => handleUserClick(e, { userId: comment.author.userId || '', nickname: comment.author.nickname })}
                    >
                      <span className="text-sm font-bold text-neutral-900 dark:text-neutral-200">{comment.author.nickname}</span>
                      <span className="text-[10px] text-neutral-400 dark:text-neutral-600">
                        {new Intl.DateTimeFormat('en-US', { hour: 'numeric', minute: 'numeric' }).format(new Date(comment.timestamp))}
                      </span>
                    </div>

                    {currentUserId === comment.author.userId && (
                      <button 
                        onClick={() => handleDeleteComment(comment.id)}
                        className="opacity-0 group-hover/comment:opacity-100 transition-opacity p-1 text-neutral-400 hover:text-red-500"
                      >
                        <Trash2 size={12} />
                      </button>
                    )}
                  </div>
                  {/* Render content with mentions */}
                  <p 
                    dir="auto"
                    className="text-sm text-neutral-600 dark:text-neutral-400 leading-relaxed whitespace-pre-wrap"
                  >
                    {renderContentWithMentions(comment.content)}
                  </p>
                </div>
              </div>
            ))}

            {comments.length === 0 && (
                <div className="text-center py-4 opacity-40 text-xs italic">
                    No comments yet. Start the conversation.
                </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Sun, Moon, Database, XCircle, Terminal, Check, Hash, X, Info, Sparkles, AtSign, Loader2, ArrowDown, Bot } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { Post } from './types';
import * as SupabaseService from './services/supabaseClient';

type FilterState = 
  | { type: 'tag'; value: string } 
  | { type: 'user'; userId: string; nickname: string } 
  | null;

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);

  const [currentUserNickname, setCurrentUserNickname] = useState<string>(() => {
    if (typeof window !== 'undefined') {
        return localStorage.getItem('echo_nickname') || 'Guest';
    }
    return 'Guest';
  });

  const [authUserId, setAuthUserId] = useState<string | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [copied, setCopied] = useState(false);
  const [aiPromptCopied, setAiPromptCopied] = useState(false);

  const [activeFilter, setActiveFilter] = useState<FilterState>(null);

  const [showDebug, setShowDebug] = useState(false);

  // Pull-to-Refresh State & Refs
  const [isRefreshing, setIsRefreshing] = useState(false);

  // Refs for direct DOM manipulation (Performance optimization)
  const mainContentRef = useRef<HTMLElement>(null);
  const refreshIndicatorRef = useRef<HTMLDivElement>(null);
  const refreshIconRef = useRef<HTMLDivElement>(null);

  // Logic Refs
  const touchStartRef = useRef(0);
  const isDraggingRef = useRef(false);
  const currentPullYRef = useRef(0);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      return saved === 'light' || saved === 'dark' ? saved : 'light';
    }
    return 'light';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('echo_nickname', currentUserNickname);
  }, [currentUserNickname]);

  // Init Auth and Load Data
  useEffect(() => {
    const init = async () => {
        try {
            setIsAuthLoading(true);
            const uid = await SupabaseService.initializeAuth();
            setAuthUserId(uid);
            await loadPosts();
        } catch (e: any) {
            console.error("Critical Init Failure", e);
            setErrorMsg(getErrorMessage(e));
        } finally {
            setIsAuthLoading(false);
            setIsLoading(false);
        }
    };
    init();
  }, []);

  const getErrorMessage = (e: any) => {
    if (!e) return "Unknown error";
    if (e.code && e.message) return `Error ${e.code}: ${e.message}`;
    if (e.message) return e.message;
    if (typeof e === 'object') return JSON.stringify(e);
    return String(e);
  };

  const loadPosts = useCallback(async () => {
    try {
      const remotePosts = await SupabaseService.fetchPosts();
      setPosts(remotePosts);
    } catch (e: any) {
      console.error("Failed to load posts", e);
      if (posts.length === 0) {
        const msg = getErrorMessage(e);
        setErrorMsg(msg);
        if (msg.includes("column") && msg.includes("does not exist")) {
            setShowDebug(true);
        }
      }
    }
  }, [posts.length]);

  // Pull to Refresh Logic (Smooth 60fps Implementation)
  const loadPostsRef = useRef(loadPosts);
  useEffect(() => { loadPostsRef.current = loadPosts; }, [loadPosts]);

  useEffect(() => {
    const handleTouchStart = (e: TouchEvent) => {
        if (window.scrollY <= 0 && !isRefreshing) {
            touchStartRef.current = e.touches[0].clientY;
            isDraggingRef.current = true;
            // Clear transitions for instant dragging response
            if (mainContentRef.current) mainContentRef.current.style.transition = 'none';
            if (refreshIndicatorRef.current) refreshIndicatorRef.current.style.transition = 'none';
            if (refreshIconRef.current) refreshIconRef.current.style.transition = 'none';
        }
    };

    const handleTouchMove = (e: TouchEvent) => {
        if (!isDraggingRef.current || isRefreshing) return;

        const currentY = e.touches[0].clientY;
        const diff = currentY - touchStartRef.current;

        // If dragging up or scrolled down, cancel
        if (diff < 0 || window.scrollY > 0) {
            isDraggingRef.current = false;
            resetDOM();
            return;
        }

        if (diff > 0) {
            if (e.cancelable) e.preventDefault(); // Stop native scroll rubberbanding

            // Smoother elastic damping formula
            // limit = max visual pull distance in pixels
            const limit = 160; 
            // damped = limit * (1 - exp(-diff / friction))
            const damped = limit * (1 - Math.exp(-diff / 250));

            currentPullYRef.current = damped;

            // Direct DOM Manipulation (No State Updates)
            if (mainContentRef.current) {
                mainContentRef.current.style.transform = `translateY(${damped}px)`;
            }

            if (refreshIndicatorRef.current) {
                // Indicator moves down but slightly slower/clamped
                const indicatorOffset = 74; // header (64) + spacing (10)
                const top = Math.min(damped, 100) + indicatorOffset;

                refreshIndicatorRef.current.style.top = `${top}px`;
                refreshIndicatorRef.current.style.opacity = `${Math.min(damped / 40, 1)}`;
                refreshIndicatorRef.current.style.transform = `scale(${Math.min(0.5 + (damped / 100), 1)})`;
            }

            if (refreshIconRef.current) {
                // Rotate based on pull distance
                refreshIconRef.current.style.transform = `rotate(${damped * 2.5}deg)`;
            }
        }
    };

    const handleTouchEnd = async () => {
        if (!isDraggingRef.current || isRefreshing) return;
        isDraggingRef.current = false;

        const triggerThreshold = 75; // px

        if (currentPullYRef.current > triggerThreshold) {
            setIsRefreshing(true);

            // Animate to "Loading" State
            if (mainContentRef.current) {
                mainContentRef.current.style.transition = 'transform 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275)';
                mainContentRef.current.style.transform = 'translateY(80px)';
            }
            if (refreshIndicatorRef.current) {
                refreshIndicatorRef.current.style.transition = 'top 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275)';
                refreshIndicatorRef.current.style.top = `${74 + 70}px`; // Center in the gap
                refreshIndicatorRef.current.style.opacity = '1';
                refreshIndicatorRef.current.style.transform = 'scale(1)';
            }

            // Haptic
            if (typeof navigator !== 'undefined' && navigator.vibrate) {
                navigator.vibrate(15);
            }

            try {
                const startTime = Date.now();
                await loadPostsRef.current();
                const elapsed = Date.now() - startTime;
                if (elapsed < 800) {
                    await new Promise(r => setTimeout(r, 800 - elapsed));
                }
            } finally {
                setIsRefreshing(false);
                resetDOM();
            }
        } else {
            // Cancel / Snap Back
            resetDOM();
        }
        currentPullYRef.current = 0;
    };

    const resetDOM = () => {
        if (mainContentRef.current) {
            mainContentRef.current.style.transition = 'transform 0.3s ease-out';
            mainContentRef.current.style.transform = 'translateY(0px)';
        }
        if (refreshIndicatorRef.current) {
            refreshIndicatorRef.current.style.transition = 'top 0.3s ease-out, opacity 0.2s ease-in';
            refreshIndicatorRef.current.style.top = '74px';
            refreshIndicatorRef.current.style.opacity = '0';
            refreshIndicatorRef.current.style.transform = 'scale(0.5)';
        }
    };

    document.addEventListener('touchstart', handleTouchStart, { passive: true });
    document.addEventListener('touchmove', handleTouchMove, { passive: false });
    document.addEventListener('touchend', handleTouchEnd, { passive: true });

    return () => {
        document.removeEventListener('touchstart', handleTouchStart);
        document.removeEventListener('touchmove', handleTouchMove);
        document.removeEventListener('touchend', handleTouchEnd);
    };
  }, [isRefreshing]);

  useEffect(() => {
    const subscription = SupabaseService.subscribeToPosts((payload) => {
      if (payload.eventType === 'INSERT' || payload.eventType === 'DELETE') {
        loadPosts();
      }
    });
    return () => { subscription?.unsubscribe(); };
  }, [loadPosts]);

  const handleUserPost = async (nickname: string, content: string, tags: string[]) => {
    if (!authUserId) return;
    setCurrentUserNickname(nickname);

    const tempId = Date.now().toString(); 
    const tempPost: Post = {
        id: tempId,
        author: { 
            nickname, 
            avatarSeed: nickname, 
            isAi: false,
            userId: authUserId
        },
        content,
        tags,
        timestamp: Date.now(),
        likes: 0,
        comments: []
    };

    setPosts(prev => [tempPost, ...prev]);

    try {
        const realPost = await SupabaseService.createPost(nickname, content, tags, authUserId);
        if (realPost) {
            setPosts(prev => prev.map(p => p.id === tempId ? realPost : p));
        }
    } catch (e: any) {
        console.error("Post failed", e);
        setPosts(prev => prev.filter(p => p.id !== tempId)); 
        alert(`Failed to post.\n\n${getErrorMessage(e)}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
    const snapshot = [...posts];
    setPosts(prev => prev.filter(p => p.id !== postId));

    if (!postId.includes('-') && /^\d+$/.test(postId)) return;

    try {
        const client = SupabaseService.getSupabase();
        const result = await SupabaseService.deletePost(client, postId, authUserId);

        if (!result.success) {
            setPosts(snapshot);
            if (result.reason === 'not_owner') {
                alert(result.error?.message || "You cannot delete this post.");
            } else if (result.reason === 'not_found') {
                alert("Post already deleted or not found.");
                loadPosts();
            } else {
                alert(result.error?.message || "Failed to delete post.");
            }
        }
    } catch (e: any) {
        setPosts(snapshot);
        console.error("Delete exception", e);
        alert(getErrorMessage(e));
    }
  };

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const copySQL = () => {
    const sql = `
-- SQL Script for Echo App (Idempotent)
create table if not exists posts (
  id uuid default gen_random_uuid() primary key,
  created_at timestamptz default now(),
  nickname text,
  content text,
  tags text[] default '{}',
  likes int default 0,
  avatar_seed text,
  user_id uuid
);
create table if not exists comments (
  id uuid default gen_random_uuid() primary key,
  created_at timestamptz default now(),
  post_id uuid references posts(id) on delete cascade,
  user_id uuid,
  nickname text,
  avatar_seed text,
  content text,
  body text
);

create index if not exists idx_posts_user_id on posts(user_id);
create index if not exists idx_comments_post_id on comments(post_id);

alter table posts enable row level security;
alter table comments enable row level security;

create or replace function set_user_id()
returns trigger as $$
begin
  if auth.uid() is not null then
    new.user_id := auth.uid();
  elsif new.user_id is null and current_setting('request.headers', true)::json->>'x-shadow-user-id' is not null then
    new.user_id := (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid;
  end if;
  return new;
end;
$$ language plpgsql;

drop trigger if exists set_user_id_posts on posts;
create trigger set_user_id_posts before insert on posts for each row execute function set_user_id();

drop trigger if exists set_user_id_comments on comments;
create trigger set_user_id_comments before insert on comments for each row execute function set_user_id();

drop policy if exists "Universal Read" on posts;
drop policy if exists "Universal Insert" on posts;
drop policy if exists "Universal Delete" on posts;
drop policy if exists "Universal Read Comments" on comments;
drop policy if exists "Universal Insert Comments" on comments;
drop policy if exists "Universal Delete Comments" on comments;

create policy "Universal Read" on posts for select using (true);
create policy "Universal Insert" on posts for insert with check (true);
create policy "Universal Delete" on posts for delete using ((auth.uid() = user_id) OR (auth.uid() IS NULL AND ((current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)));

create policy "Universal Read Comments" on comments for select using (true);
create policy "Universal Insert Comments" on comments for insert with check (true);
create policy "Universal Delete Comments" on comments for delete using ((auth.uid() = user_id) OR (auth.uid() IS NULL AND ((current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)));
`;
    navigator.clipboard.writeText(sql);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const copyAiPrompt = () => {
      const prompt = `I am building a React app with Supabase. I have a 'Shadow Login' system where guest users are identified by a 'x-shadow-user-id' header (which contains a UUID) if they are not logged in via Supabase Auth. Please write a SQL script to configure my database that creates 'posts' and 'comments' tables with a 'user_id' UUID column, enables RLS, and creates a trigger to auto-set 'user_id' from auth.uid() OR the 'x-shadow-user-id' header. Allow public reads/inserts, but restrict deletes to owners.`;
      navigator.clipboard.writeText(prompt);
      setAiPromptCopied(true);
      setTimeout(() => setAiPromptCopied(false), 2000);
  };

  const handleTagClick = (tag: string) => {
      const rawTag = tag.replace(/^#/, '');
      setActiveFilter({ type: 'tag', value: rawTag });
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleUserClick = (user: { userId: string; nickname: string }) => {
      if (!user.userId) return;
      setActiveFilter({ type: 'user', userId: user.userId, nickname: user.nickname });
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const clearFilter = () => setActiveFilter(null);

  const filteredPosts = useMemo(() => {
      if (!activeFilter) return posts;
      if (activeFilter.type === 'tag') {
          return posts.filter(post => 
              post.tags.some(t => t.toLowerCase() === activeFilter.value.toLowerCase())
          );
      }
      if (activeFilter.type === 'user') {
          return posts.filter(post => post.author.userId === activeFilter.userId);
      }
      return posts;
  }, [posts, activeFilter]);

  const trendingTopics = useMemo(() => {
    const counts: Record<string, number> = {};
    posts.forEach(post => {
        if (post.tags && Array.isArray(post.tags)) {
            post.tags.forEach(tag => {
                if(tag) counts[tag] = (counts[tag] || 0) + 1;
            });
        }
    });
    const sorted = Object.entries(counts).sort((a, b) => b[1] - a[1]);
    return sorted.slice(0, 10).map(t => '#' + t[0]);
  }, [posts]);

  const isOwner = (post: Post) => {
    if (!authUserId) return false;
    return post.author.userId === authUserId;
  };

  const statusColor = authUserId && !authUserId.includes('-') && authUserId.length > 30
      ? 'text-green-500' 
      : 'text-yellow-500';

  return (
    <div className="min-h-screen transition-colors duration-300 bg-[#FAFAFA] text-neutral-900 dark:bg-[#050505] dark:text-white overflow-hidden">

      {/* Sticky Header */}
      <header className="fixed top-0 z-50 w-full backdrop-blur-xl bg-white/80 dark:bg-black/80 border-b border-neutral-200 dark:border-white/10">
        <div className="max-w-2xl mx-auto px-4 h-16 flex items-center justify-between">
            <div 
                onClick={() => { clearFilter(); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
                className="flex items-center gap-2 cursor-pointer group"
            >
                <span className="font-bold text-xl tracking-tight">Echo</span>
            </div>

            <div className="flex items-center gap-3">
                <button 
                    onClick={() => setShowDebug(!showDebug)}
                    className={`p-2 rounded-full transition-colors ${showDebug ? 'bg-neutral-100 dark:bg-white/10 text-black dark:text-white' : 'text-neutral-400 hover:text-black dark:hover:text-white'}`}
                >
                    <Info size={20} />
                </button>
                <button 
                    onClick={toggleTheme} 
                    className="p-2 rounded-full text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-white/10 transition-colors"
                >
                    {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
                </button>
            </div>
        </div>
      </header>

      {/* Optimized Pull To Refresh Indicator */}
      <div 
        ref={refreshIndicatorRef}
        className="fixed left-0 right-0 z-40 flex justify-center pointer-events-none"
        style={{ 
            top: '74px', // Start hidden or just at edge
            opacity: 0,
            transform: 'scale(0.5)'
            // Transition is handled by refs in JS
        }}
      >
        <div 
            className="bg-white dark:bg-[#1E1E1E] rounded-full p-2.5 shadow-md border border-neutral-100 dark:border-neutral-700 flex items-center justify-center"
        >
            {isRefreshing ? (
                <Loader2 size={20} className="text-black dark:text-white animate-spin" />
            ) : (
                <div ref={refreshIconRef}>
                    <ArrowDown size={20} className="text-black dark:text-white" />
                </div>
            )}
        </div>
      </div>

      {/* Main Content Wrapper */}
      <main 
        ref={mainContentRef}
        className="max-w-2xl mx-auto px-4 py-8 pt-24 min-h-screen relative"
        // Style handled by JS refs for performance
      >

        {/* Error Banner */}
        {errorMsg && (
            <div className="mb-8 p-4 rounded-2xl border border-red-200 bg-red-50 text-red-800 dark:border-red-900/50 dark:bg-red-900/20 dark:text-red-200 shadow-sm animate-in slide-in-from-top-4">
                <div className="flex items-start gap-3">
                    <XCircle className="shrink-0 mt-0.5" size={20} />
                    <div className="space-y-2 w-full">
                        <h3 className="font-bold text-sm">Connection Error</h3>
                        <p className="text-xs opacity-90 font-mono break-all">{errorMsg}</p>
                        {(errorMsg.includes("column") && errorMsg.includes("does not exist")) && (
                            <div className="mt-3 p-2 bg-white/50 dark:bg-black/20 rounded border border-red-200 dark:border-red-800/50 text-xs">
                                <strong>Tip:</strong> Database schema issue detected. Click "Copy SQL Fix".
                            </div>
                        )}
                        <button 
                            onClick={copySQL}
                            className="mt-2 text-xs bg-white dark:bg-black px-3 py-1.5 rounded-lg border border-red-100 dark:border-red-900/30 font-medium flex items-center gap-2 w-fit hover:border-red-300 transition-colors"
                        >
                            {copied ? <Check size={12} className="text-green-500" /> : <Database size={12} />}
                            {copied ? 'SQL Copied' : 'Copy SQL Fix'}
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Debug / Status Panel */}
        {showDebug && (
            <div className="mb-8 p-6 rounded-[32px] bg-white dark:bg-[#0F0F0F] border border-neutral-200 dark:border-neutral-800 shadow-sm">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="font-bold text-lg">System Status</h3>
                    <div className={`flex items-center gap-2 text-xs font-bold px-3 py-1 rounded-full bg-neutral-100 dark:bg-neutral-800 ${statusColor}`}>
                        <div className="w-2 h-2 rounded-full bg-current animate-pulse" />
                        {authUserId && !authUserId.includes('-') && authUserId.length > 30 ? 'AUTHENTICATED' : 'SHADOW MODE'}
                    </div>
                </div>
                <div className="space-y-4">
                    <div>
                        <div className="text-xs text-neutral-500 uppercase font-bold tracking-wider mb-1">User ID</div>
                        <code className="text-xs font-mono bg-neutral-100 dark:bg-black px-2 py-1 rounded block overflow-hidden text-ellipsis">{authUserId || 'Loading...'}</code>
                    </div>
                    <div>
                        <div className="text-xs text-neutral-500 uppercase font-bold tracking-wider mb-2">Supabase Tools</div>
                        <div className="flex flex-col gap-2">
                             <button 
                                onClick={copySQL}
                                className="text-xs flex items-center gap-2 px-4 py-2 bg-black text-white dark:bg-white dark:text-black rounded-full font-medium active:scale-95 transition-transform w-full justify-center"
                            >
                                {copied ? <Check size={14} className="text-green-500" /> : <Terminal size={14} />}
                                {copied ? 'Copied SQL' : 'Copy SQL Script'}
                            </button>
                            <button 
                                onClick={copyAiPrompt}
                                className="text-xs flex items-center gap-2 px-4 py-2 bg-neutral-100 text-neutral-900 dark:bg-neutral-800 dark:text-white rounded-full font-medium active:scale-95 transition-transform w-full justify-center"
                            >
                                {aiPromptCopied ? <Check size={14} className="text-green-500" /> : <Bot size={14} />}
                                {aiPromptCopied ? 'Copied Prompt' : 'Copy Prompt for Supabase AI'}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}

        {/* Input Area (Hidden if filtering) */}
        {!activeFilter && !isAuthLoading && (
            <>
                <CreatePost onPost={handleUserPost} defaultNickname={currentUserNickname} />

                {trendingTopics.length > 0 && (
                    <div className="flex items-center gap-2 overflow-x-auto pb-4 pt-2 no-scrollbar mask-gradient">
                        <div className="flex items-center gap-2 pr-4">
                            <Sparkles size={14} className="text-neutral-400" />
                            <span className="text-xs font-bold text-neutral-400 uppercase tracking-wider whitespace-nowrap">Trending:</span>
                        </div>
                        {trendingTopics.map((topic, i) => (
                            <button
                                key={i}
                                onClick={() => handleTagClick(topic)}
                                className="px-3 py-1.5 rounded-full bg-white border border-neutral-200 text-xs font-medium text-neutral-600 hover:border-black hover:text-black whitespace-nowrap transition-all
                                        dark:bg-[#111] dark:border-neutral-800 dark:text-neutral-400 dark:hover:border-white dark:hover:text-white"
                            >
                                {topic}
                            </button>
                        ))}
                    </div>
                )}
            </>
        )}

        {/* Active Filter Banner */}
        {activeFilter && (
            <div className="mb-6 flex items-center justify-between p-1 pl-1 pr-4 rounded-full bg-black text-white dark:bg-white dark:text-black animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-3">
                    <div className="p-3 rounded-full bg-white/20 dark:bg-black/10">
                        {activeFilter.type === 'tag' ? <Hash size={20} /> : <AtSign size={20} />}
                    </div>
                    <div>
                        <div className="text-[10px] uppercase font-bold opacity-60 tracking-wider">
                            {activeFilter.type === 'tag' ? 'Viewing Tag' : 'Viewing User'}
                        </div>
                        <h3 className="font-bold text-sm">
                            {activeFilter.type === 'tag' ? `#${activeFilter.value}` : activeFilter.nickname}
                        </h3>
                    </div>
                </div>
                <button onClick={clearFilter} className="p-2 rounded-full hover:bg-white/20 dark:hover:bg-black/10 transition-colors">
                    <X size={18} />
                </button>
            </div>
        )}

        {/* Feed */}
        <div className="space-y-4 min-h-[50vh]">
            {(isLoading || isAuthLoading) && posts.length === 0 ? (
                 <div className="flex flex-col items-center justify-center py-20 opacity-50 space-y-4">
                    <div className="w-8 h-8 border-2 border-current border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-sm font-medium">Loading feed...</p>
                 </div>
            ) : filteredPosts.length === 0 ? (
                <div className="text-center py-20 opacity-60">
                    <div className="text-4xl mb-4 grayscale flex justify-center">
                        {activeFilter ? (activeFilter.type === 'tag' ? '🔭' : '👤') : '🎙️'}
                    </div>
                    <h2 className="text-lg font-medium mb-1">
                        {activeFilter ? 'No signals found' : 'Echo is quiet'}
                    </h2>
                    <p className="text-sm text-neutral-500">
                        {activeFilter 
                            ? (activeFilter.type === 'tag' ? `Be the first to tag #${activeFilter.value}` : `No posts from ${activeFilter.nickname} yet`)
                            : 'Start the conversation'}
                    </p>
                    {activeFilter && (
                        <button onClick={clearFilter} className="mt-4 text-sm font-bold underline hover:text-black dark:hover:text-white">
                            View All Posts
                        </button>
                    )}
                </div>
            ) : (
                filteredPosts.map(post => (
                    <PostCard 
                        key={post.id} 
                        post={post} 
                        isUser={isOwner(post)} 
                        currentUserId={authUserId}
                        onDelete={handleDeletePost}
                        onTagClick={handleTagClick}
                        onUserClick={handleUserClick}
                    />
                ))
            )}
        </div>

        {/* Footer */}
        <footer className="mt-20 py-8 border-t border-neutral-100 dark:border-white/5 flex flex-col items-center gap-4 text-neutral-400">
            <div className="flex items-center gap-2 text-xs font-medium">
                <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse" />
                Live Connection
            </div>
            <p className="text-[10px] uppercase tracking-widest opacity-50">
                ECHO by iter • DECENTRALIZED FEED
            </p>
        </footer>

      </main>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { Send, Hash, AtSign, X } from 'lucide-react';
import { DEFAULT_AVATAR_URL } from '../constants';

interface CreatePostProps {
  onPost: (nickname: string, content: string, tags: string[]) => void;
  defaultNickname: string;
}

export const CreatePost: React.FC<CreatePostProps> = ({ onPost, defaultNickname }) => {
  const [nickname, setNickname] = useState(defaultNickname);
  const [content, setContent] = useState('');
  const [tags, setTags] = useState<string[]>([]);
  const [tagInput, setTagInput] = useState('');
  const [isFocused, setIsFocused] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // CHARACTER LIMIT CONFIGURATION
  const MAX_CHARS = 800;

  const charCount = content.length;
  // We force the content to never exceed MAX_CHARS, so this is mainly for full-circle logic
  const isAtLimit = charCount >= MAX_CHARS;
  const remaining = Math.max(0, MAX_CHARS - charCount);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = textareaRef.current.scrollHeight + 'px';
    }
  }, [content]);

  const handleContentChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const val = e.target.value;
    // Strict enforcement
    if (val.length <= MAX_CHARS) {
        setContent(val);
    } else {
        // Handle paste overflow
        setContent(val.slice(0, MAX_CHARS));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!nickname.trim() || !content.trim()) return;

    // Merge explicit tags with hashtags in content
    const contentHashtags = content.match(/#[\w]+/g)?.map(t => t.replace('#', '')) || [];

    // Process current tag input if any exists but wasn't "entered"
    let currentInputTags: string[] = [];
    if (tagInput.trim()) {
       currentInputTags = tagInput.split(/[\s,]+/).map(t => t.trim().replace(/^#/, '')).filter(Boolean);
    }

    const finalTags = [...new Set([...tags, ...currentInputTags, ...contentHashtags])];

    onPost(nickname, content, finalTags);

    // Reset
    setContent('');
    setTags([]);
    setTagInput('');
    setIsFocused(false);
    if (textareaRef.current) textareaRef.current.style.height = 'auto';
  };

  const handleTagKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (['Enter', ' ', ','].includes(e.key)) {
      e.preventDefault();
      const newTags = tagInput.split(/[\s,]+/).map(t => t.trim().replace(/^#/, '')).filter(t => t.length > 0);
      if (newTags.length > 0) {
        setTags(prev => [...new Set([...prev, ...newTags])]); // No duplicates in chip list
        setTagInput('');
      }
    } else if (e.key === 'Backspace' && tagInput === '' && tags.length > 0) {
      setTags(prev => prev.slice(0, -1));
    }
  };

  const removeTag = (tagToRemove: string) => {
    setTags(prev => prev.filter(t => t !== tagToRemove));
  };

  const handleFocus = () => setIsFocused(true);

  // Handle outside click to collapse if empty
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        if (!content.trim() && tags.length === 0 && !tagInput.trim()) {
           setIsFocused(false);
        }
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [content, tags, tagInput]);

  const isExpanded = isFocused || content.length > 0 || tags.length > 0 || tagInput.length > 0;

  // Circular Progress Calculation based on CHARACTERS
  const radius = 14; 
  const circumference = 2 * Math.PI * radius;
  const progressPercentage = Math.min(100, (charCount / MAX_CHARS) * 100);
  const strokeDashoffset = circumference - (progressPercentage / 100) * circumference;

  // Color Logic
  // Green at start, Yellow after 80%, Red at limit
  const progressColor = isAtLimit 
    ? 'text-red-500' 
    : charCount > MAX_CHARS * 0.8 
        ? 'text-yellow-500' 
        : 'text-green-500';

  return (
    <div 
        ref={containerRef}
        className={`
            relative transition-all duration-300 ease-out
            bg-white dark:bg-[#0F0F0F] 
            rounded-[28px] 
            ${isExpanded 
                ? 'shadow-xl shadow-black/5 ring-1 ring-black/5 dark:shadow-white/5 dark:ring-white/10 p-6 mb-8' 
                : 'shadow-sm border border-neutral-200 dark:border-neutral-800 p-4 mb-6 hover:border-neutral-300 dark:hover:border-neutral-700'
            }
        `}
    >
        {/* Header: Identity */}
        <div className={`flex items-center gap-3 mb-4 transition-all duration-300 ${isExpanded ? 'opacity-100' : 'opacity-80'}`}>
            <div className="relative">
                <img 
                    src={DEFAULT_AVATAR_URL(nickname || 'Guest')} 
                    alt="Avatar"
                    className="w-10 h-10 rounded-full border border-neutral-100 dark:border-neutral-800 bg-neutral-50 dark:bg-neutral-900 object-cover"
                />
                <div className="absolute -bottom-1 -right-1 bg-black dark:bg-white text-white dark:text-black rounded-full p-1 border-2 border-white dark:border-black">
                   <AtSign size={10} />
                </div>
            </div>

            <div className="flex flex-col w-full">
                <span className="text-[10px] font-bold text-neutral-400 uppercase tracking-wider mb-0.5">Posting as</span>
                <input
                    type="text"
                    value={nickname}
                    onChange={(e) => setNickname(e.target.value)}
                    onFocus={handleFocus}
                    placeholder="Anonymous"
                    maxLength={20}
                    className="bg-transparent border-none outline-none p-0 text-sm font-bold text-neutral-900 dark:text-neutral-100 placeholder-neutral-400 w-full"
                />
            </div>
        </div>

        {/* Text Editor */}
        <textarea
            ref={textareaRef}
            dir="auto"
            value={content}
            maxLength={MAX_CHARS}
            onChange={handleContentChange}
            onFocus={handleFocus}
            placeholder="What's on your mind?"
            className={`
                w-full bg-transparent border-none outline-none focus:ring-0 resize-none 
                text-lg leading-relaxed
                text-neutral-900 placeholder-neutral-400
                dark:text-white dark:placeholder-neutral-600
                min-h-[60px] max-h-[400px]
                transition-all duration-200
            `}
        />

        {/* Interactive Tags */}
        {(isExpanded) && (
            <div className="mt-3 flex flex-wrap gap-2 items-center animate-in fade-in slide-in-from-top-2">
                {tags.map(tag => (
                    <span key={tag} className="inline-flex items-center gap-1 px-2.5 py-1 rounded-lg bg-neutral-100 dark:bg-neutral-800 text-neutral-700 dark:text-neutral-300 text-xs font-medium border border-neutral-200 dark:border-neutral-700">
                        #{tag}
                        <button onClick={() => removeTag(tag)} className="hover:text-red-500 rounded-full p-0.5 transition-colors">
                            <X size={12} />
                        </button>
                    </span>
                ))}
                <div className="flex items-center gap-2 flex-1 min-w-[120px]">
                    <Hash size={14} className="text-neutral-400" />
                    <input 
                        type="text"
                        value={tagInput}
                        onChange={(e) => setTagInput(e.target.value)}
                        onKeyDown={handleTagKeyDown}
                        onFocus={handleFocus}
                        placeholder="Add tags..."
                        className="bg-transparent border-none outline-none text-sm text-neutral-600 dark:text-neutral-300 placeholder-neutral-400 flex-1"
                    />
                </div>
            </div>
        )}

        {/* Footer Actions */}
        {(isExpanded) && (
            <div className="flex items-center justify-end mt-5 pt-3 border-t border-neutral-100 dark:border-white/5 animate-in fade-in">
                {/* Submit Area */}
                <div className="flex items-center gap-4">
                    {/* Character Count Indicator */}
                    <div className="relative w-10 h-10 flex items-center justify-center">
                        <svg className="w-full h-full transform -rotate-90" viewBox="0 0 36 36">
                            {/* Background Circle */}
                            <circle
                                cx="18"
                                cy="18"
                                r={radius}
                                stroke="currentColor"
                                strokeWidth="2"
                                fill="transparent"
                                className="text-neutral-100 dark:text-neutral-800"
                            />
                            {/* Progress Circle */}
                            <circle
                                cx="18"
                                cy="18"
                                r={radius}
                                stroke="currentColor"
                                strokeWidth="2"
                                fill="transparent"
                                strokeDasharray={circumference}
                                strokeDashoffset={strokeDashoffset}
                                strokeLinecap="round"
                                className={`${progressColor} transition-all duration-300`}
                            />
                        </svg>

                        {/* Always show remaining count if there is content */}
                        <span className={`absolute text-[10px] font-bold ${isAtLimit ? 'text-red-500' : 'text-neutral-400'} transition-colors duration-200`}>
                            {remaining}
                        </span>
                    </div>

                    <button 
                        onClick={handleSubmit}
                        disabled={!content.trim() || !nickname.trim()}
                        className="
                            group flex items-center gap-2 px-5 py-2 rounded-full font-bold text-sm transition-all duration-200
                            bg-black text-white hover:bg-neutral-800 hover:scale-105 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:scale-100
                            dark:bg-white dark:text-black dark:hover:bg-neutral-200
                        "
                    >
                        <span>Post</span>
                        <Send size={16} className="group-hover:translate-x-0.5 transition-transform" />
                    </button>
                </div>
            </div>
        )}
    </div>
  );
};
